        printf("Stack Overflow!\n");
        return;
    }

    s->items[++s->top] = x;
}

int pop(stack* s) {
    if (s == NULL) {
        fprintf(stderr, "NULL pointer passed to pop\n");
        exit(EXIT_FAILURE);
    }
    if(is_empty(s)) {
        printf("Stack Underflow!\n");
        return -1;
    }

    return s->items[s->top--];
