    unsigned capacity;
    int* array;
};

/* Function to create a queue */
struct Queue* createQueue(unsigned capacity) {
    struct Queue* queue = (struct Queue*)malloc(sizeof(struct Queue));
    if (!queue) return NULL; // Check if malloc failed
    queue->capacity = capacity;
    queue->front = queue->size = 0;
    queue->rear = capacity - 1;  /* Important point of consideration while implementing circular queue */
    queue->array = (int*)malloc(queue->capacity * sizeof(int));
    if (!queue->array) { // Check if malloc failed
        free(queue);
        return NULL;
    }
    return queue;
}

/* Function to check if queue is full */
int isFull(struct Queue* queue) {
    if (!queue) return 1; // Treat as full if queue is NULL
    return (queue->size == queue->capacity);
}

/* Function to check if queue is empty */
int isEmpty(struct Queue* queue) {
    if (!queue) return 1; // Treat as empty if queue is NULL
    return (queue->size == 0);
}

/* Function to add an element to the queue (enqueue) */
void enqueue(struct Queue* queue, int item) {
    if (!queue || isFull(queue))
        return;  // Overflow condition or NULL queue
    queue->rear = (queue->rear + 1) % queue->capacity;  // Circular increment to provide array like behavior
    queue->array[queue->rear] = item;
    queue->size++;
    printf("%d enqueued to queue\n", item);
}

