    if (!queue || isEmpty(queue))
        return -1;  // Underflow condition or NULL queue
    return queue->array[queue->front];
}

/* Function to obtain the rear element of the queue */
int rear(struct Queue* queue) {
    if (!queue || isEmpty(queue))
        return -1;  // Underflow condition or NULL queue
    return queue->array[queue->rear];
}

